using Microsoft.ML.Data;

namespace ChurnPredictor.Models;

public class CustomerData
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    public string Churned { get; set; } = string.Empty;
}

public class CustomerDataWithLabel
{
    public float Age { get; set; }
    public float Income { get; set; }
    public string Region { get; set; } = string.Empty;
    public float PurchaseHistory { get; set; }

    [ColumnName("Label")]
    public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

using ChurnPredictor.Models;
using Microsoft.ML;
using Microsoft.ML.Data;

namespace ChurnPredictor.Services;

public class ModelMetrics
{
    public double Accuracy { get; set; }
    public double Auc { get; set; }
    public double F1Score { get; set; }
    public double PositivePrecision { get; set; }
    public double PositiveRecall { get; set; }
}

public class ChurnModelService
{
    private readonly ILogger<ChurnModelService> _logger;
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;

    public ModelMetrics Metrics { get; }

    public ChurnModelService(ILogger<ChurnModelService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _mlContext = new MLContext(seed: 42);

        var csvPath = Path.Combine(env.ContentRootPath, "Data", "customers.csv");
        _logger.LogInformation("Loading data from {Path}", csvPath);

        // Load raw CSV data
        var rawData = _mlContext.Data.LoadFromTextFile<CustomerData>(
            csvPath, hasHeader: true, separatorChar: ',');

        // Convert string Churned ("Yes"/"No") to bool Label in-memory
        var rows = _mlContext.Data.CreateEnumerable<CustomerData>(rawData, reuseRowObject: false)
            .Select(r => new CustomerDataWithLabel
            {
                Age = r.Age,
                Income = r.Income,
                Region = r.Region,
                PurchaseHistory = r.PurchaseHistory,
                Label = string.Equals(r.Churned, "Yes", StringComparison.OrdinalIgnoreCase)
            })
            .ToList();

        var data = _mlContext.Data.LoadFromEnumerable(rows);

        // Train/test split
        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Build pipeline: OneHotEncode Region, concatenate features, train with FastTree
        var pipeline = _mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
            .Append(_mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
            .Append(_mlContext.BinaryClassification.Trainers.FastTree());

        _logger.LogInformation("Training churn prediction model...");
        _model = pipeline.Fit(split.TrainSet);

        // Evaluate
        var predictions = _model.Transform(split.TestSet);
        var eval = _mlContext.BinaryClassification.Evaluate(predictions);

        Metrics = new ModelMetrics
        {
            Accuracy = eval.Accuracy,
            Auc = eval.AreaUnderRocCurve,
            F1Score = eval.F1Score,
            PositivePrecision = eval.PositivePrecision,
            PositiveRecall = eval.PositiveRecall
        };

        _logger.LogInformation(
            "Model trained — Accuracy: {Accuracy:F4}, AUC: {AUC:F4}, F1: {F1:F4}",
            Metrics.Accuracy, Metrics.Auc, Metrics.F1Score);
    }

    public MLContext MlContext => _mlContext;
    public ITransformer Model => _model;
}

