using ChurnPredictor.Models;
using ChurnPredictor.Services;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// Register the model training service as a singleton (trains once at startup)
builder.Services.AddSingleton<ChurnModelService>();

// Register PredictionEnginePool using the trained model
builder.Services.AddPredictionEnginePool<CustomerDataWithLabel, ChurnPrediction>();
builder.Services.AddOptions<PredictionEnginePoolOptions<CustomerDataWithLabel, ChurnPrediction>>()
    .Configure<ChurnModelService>((options, svc) =>
    {
        options.ModelLoader = svc.MlContext.Model.CreateModelLoader(svc.Model, svc.MlContext.Data.LoadFromEnumerable(Array.Empty<CustomerDataWithLabel>()).Schema);
    });

var app = builder.Build();

// Force model training at startup so metrics are available immediately
app.Services.GetRequiredService<ChurnModelService>();

app.MapGet("/", () => "Hello");

app.MapPost("/predict", (CustomerInput input, PredictionEnginePool<CustomerDataWithLabel, ChurnPrediction> pool) =>
{
    var customerData = new CustomerDataWithLabel
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory,
        Label = false
    };

    var prediction = pool.Predict(customerData);

    return Results.Ok(new
    {
        predictedLabel = prediction.PredictedLabel,
        willChurn = prediction.PredictedLabel ? "Yes" : "No",
        probability = prediction.Probability,
        score = prediction.Score
    });
});

app.MapGet("/metrics", (ChurnModelService svc) =>
{
    return Results.Ok(svc.Metrics);
});

app.Run();

public record CustomerInput(float Age, float Income, string Region, float PurchaseHistory);

