// With very small datasets, train/test split may produce a test set without
// both classes, so we wrap evaluation in a try/catch and fall back to training-set metrics.
var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

// Build pipeline: OneHotEncode Region, concatenate features, train with FastTree
var pipeline = _mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
    .Append(_mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(_mlContext.BinaryClassification.Trainers.FastTree());

_logger.LogInformation("Training churn prediction model...");
_model = pipeline.Fit(split.TrainSet);

// Evaluate — prefer test set but fall back to training set for tiny datasets
CalibratedBinaryClassificationMetrics eval;
try
{
    var testPredictions = _model.Transform(split.TestSet);
    eval = _mlContext.BinaryClassification.Evaluate(testPredictions);
}
catch (ArgumentOutOfRangeException)
{
    _logger.LogWarning("Test set too small for evaluation; using training set metrics instead.");
    var trainPredictions = _model.Transform(split.TrainSet);
    eval = _mlContext.BinaryClassification.Evaluate(trainPredictions);
}

