1. using ChurnPredictor.Models;
2. using Microsoft.ML;
3. using Microsoft.ML.Data;
4. 
5. namespace ChurnPredictor.Services;
6. 
7. public class ModelMetrics
8. {
9.     public double Accuracy { get; set; }
10.     public double Auc { get; set; }
11.     public double F1Score { get; set; }
12.     public double PositivePrecision { get; set; }
13.     public double PositiveRecall { get; set; }
14. }
15. 
16. public class ChurnModelService
17. {
18.     private readonly ILogger<ChurnModelService> _logger;
19.     private readonly MLContext _mlContext;
20.     private readonly ITransformer _model;
21. 
22.     public ModelMetrics Metrics { get; }
23. 
24.     public ChurnModelService(ILogger<ChurnModelService> logger, IWebHostEnvironment env)
25.     {
26.         _logger = logger;
27.         _mlContext = new MLContext(seed: 42);
28. 
29.         var csvPath = Path.Combine(env.ContentRootPath, "Data", "customers.csv");
30.         _logger.LogInformation("Loading data from {Path}", csvPath);
31. 
32.         // Load raw CSV data
33.         var rawData = _mlContext.Data.LoadFromTextFile<CustomerData>(
34.             csvPath, hasHeader: true, separatorChar: ',');
35. 
36.         // Convert string Churned ("Yes"/"No") to bool Label in-memory
37.         var rows = _mlContext.Data.CreateEnumerable<CustomerData>(rawData, reuseRowObject: false)
38.             .Select(r => new CustomerDataWithLabel
39.             {
40.                 Age = r.Age,
41.                 Income = r.Income,
42.                 Region = r.Region,
43.                 PurchaseHistory = r.PurchaseHistory,
44.                 Label = string.Equals(r.Churned, "Yes", StringComparison.OrdinalIgnoreCase)
45.             })
46.             .ToList();
47. 
48.         var data = _mlContext.Data.LoadFromEnumerable(rows);
49. 
50.         // With very small datasets, train/test split may produce a test set without
51.         // both classes, so we wrap evaluation in a try/catch and fall back to training-set metrics.
52.         var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
53. 
54.         // Build pipeline: OneHotEncode Region, concatenate features, train with FastTree
55.         var pipeline = _mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
56.             .Append(_mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
57.             .Append(_mlContext.BinaryClassification.Trainers.FastTree());
58. 
59.         _logger.LogInformation("Training churn prediction model...");
60.         _model = pipeline.Fit(split.TrainSet);
61. 
62.         // Evaluate — prefer test set but fall back to training set for tiny datasets
63.         CalibratedBinaryClassificationMetrics eval;
64.         try
65.         {
66.             var testPredictions = _model.Transform(split.TestSet);
67.             eval = _mlContext.BinaryClassification.Evaluate(testPredictions);
68.         }
69.         catch (ArgumentOutOfRangeException)
70.         {
71.             _logger.LogWarning("Test set too small for evaluation; using training set metrics instead.");
72.             var trainPredictions = _model.Transform(split.TrainSet);
73.             eval = _mlContext.BinaryClassification.Evaluate(trainPredictions);
74.         }
75. 
76.         Metrics = new ModelMetrics
77.         {
78.             Accuracy = eval.Accuracy,
79.             Auc = eval.AreaUnderRocCurve,
80.             F1Score = eval.F1Score,
81.             PositivePrecision = eval.PositivePrecision,
82.             PositiveRecall = eval.PositiveRecall
83.         };
84. 
85.         _logger.LogInformation(
86.             "Model trained — Accuracy: {Accuracy:F4}, AUC: {AUC:F4}, F1: {F1:F4}",
87.             Metrics.Accuracy, Metrics.Auc, Metrics.F1Score);
88. 
89.         SaveModel(data);
90.     }
91. 
92.     public string ModelPath { get; private set; } = string.Empty;
93. 
94.     private void SaveModel(IDataView dataSchema)
95.     {
96.         ModelPath = Path.Combine(Path.GetDirectoryName(typeof(ChurnModelService).Assembly.Location)!, "churn_model.zip");
97.         _mlContext.Model.Save(_model, dataSchema.Schema, ModelPath);
98.         _logger.LogInformation("Model saved to {Path}", ModelPath);
99.     }
100. 
101.     public MLContext MlContext => _mlContext;
102. }
103.

