     public double PositiveRecall { get; set; }
 }

 public class ChurnModelService
 {
     private readonly ILogger<ChurnModelService> _logger;
     private readonly MLContext _mlContext;
     private readonly ITransformer _model;

     public ModelMetrics Metrics { get; }

     public ChurnModelService(ILogger<ChurnModelService> logger, IWebHostEnvironment env)
     {
         _logger = logger;
         _mlContext = new MLContext(seed: 42);

         var csvPath = Path.Combine(env.ContentRootPath, "Data", "customers.csv");
         _logger.LogInformation("Loading data from {Path}", csvPath);

         // Load raw CSV data
         var rawData = _mlContext.Data.LoadFromTextFile<CustomerData>(
             csvPath, hasHeader: true, separatorChar: ',');

