         catch (ArgumentOutOfRangeException)
         {
             _logger.LogWarning("Test set too small for evaluation; using training set metrics instead.");
             var trainPredictions = _model.Transform(split.TrainSet);
             eval = _mlContext.BinaryClassification.Evaluate(trainPredictions);
         }

         Metrics = new ModelMetrics
         {
             Accuracy = eval.Accuracy,
             Auc = eval.AreaUnderRocCurve,
             F1Score = eval.F1Score,
             PositivePrecision = eval.PositivePrecision,
             PositiveRecall = eval.PositiveRecall
         };

         _logger.LogInformation(
             "Model trained — Accuracy: {Accuracy:F4}, AUC: {AUC:F4}, F1: {F1:F4}",
             Metrics.Accuracy, Metrics.Auc, Metrics.F1Score);

         SaveModel(data);
     }

     public string ModelPath { get; private set; } = string.Empty;

     private void SaveModel(IDataView dataSchema)
     {
         ModelPath = Path.Combine(Path.GetDirectoryName(typeof(ChurnModelService).Assembly.Location)!, "churn_model.zip");
         _mlContext.Model.Save(_model, dataSchema.Schema, ModelPath);
         _logger.LogInformation("Model saved to {Path}", ModelPath);
     }

     public MLContext MlContext => _mlContext;
 }

